"use strict";(self.webpackChunkelectronjs=self.webpackChunkelectronjs||[]).push([["30545"],{18908:function(e,t,o){o.r(t),o.d(t,{frontMatter:()=>s,toc:()=>c,default:()=>d,metadata:()=>i,assets:()=>l,contentTitle:()=>a});var i=JSON.parse('{"id":"latest/why-electron","title":"Why Electron","description":"Electron is a framework enabling developers to build cross-platform desktop applications for macOS, Windows, and Linux by combining web technologies (HTML, JavaScript, CSS) with Node.js and native code. It is open-source, MIT-licensed, and free for both commercial and personal use. In this document, we\u2019ll explain why companies and developers choose Electron.","source":"@site/docs/latest/why-electron.md","sourceDirName":"latest","slug":"/latest/why-electron","permalink":"/docs/latest/why-electron","draft":false,"unlisted":false,"editUrl":"https://github.com/electron/electron/edit/main/docs/why-electron.md","tags":[],"version":"current","frontMatter":{"title":"Why Electron","description":"Electron is a framework enabling developers to build cross-platform desktop applications for macOS, Windows, and Linux by combining web technologies (HTML, JavaScript, CSS) with Node.js and native code. It is open-source, MIT-licensed, and free for both commercial and personal use. In this document, we\u2019ll explain why companies and developers choose Electron.","slug":"why-electron","hide_title":false},"sidebar":"docs","previous":{"title":"Introduction","permalink":"/docs/latest/"},"next":{"title":"Prerequisites","permalink":"/docs/latest/tutorial/tutorial-prerequisites"}}'),n=o(74848),r=o(84429);let s={title:"Why Electron",description:"Electron is a framework enabling developers to build cross-platform desktop applications for macOS, Windows, and Linux by combining web technologies (HTML, JavaScript, CSS) with Node.js and native code. It is open-source, MIT-licensed, and free for both commercial and personal use. In this document, we\u2019ll explain why companies and developers choose Electron.",slug:"why-electron",hide_title:!1},a="Why Electron",l={},c=[{value:"Why choose web technologies",id:"why-choose-web-technologies",level:2},{value:"Versatility",id:"versatility",level:3},{value:"Reliability",id:"reliability",level:3},{value:"Interoperability",id:"interoperability",level:3},{value:"Ubiquity",id:"ubiquity",level:3},{value:"Why choose Electron",id:"why-choose-electron",level:2},{value:"Enterprise-grade",id:"enterprise-grade",level:3},{value:"Mature",id:"mature",level:3},{value:"Stability, security, performance",id:"stability-security-performance",level:3},{value:"Why bundle anything at all",id:"why-bundle-anything-at-all",level:4},{value:"Why bundle Chromium and Node.js",id:"why-bundle-chromium-and-nodejs",level:4},{value:"Developer experience",id:"developer-experience",level:3},{value:"Why choose something else",id:"why-choose-something-else",level:2}];function h(e){let t={a:"a",code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",h4:"h4",header:"header",hr:"hr",li:"li",p:"p",strong:"strong",ul:"ul",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"why-electron",children:"Why Electron"})}),"\n",(0,n.jsx)(t.p,{children:"Electron is a framework enabling developers to build cross-platform desktop applications for macOS, Windows, and Linux by combining web technologies (HTML, JavaScript, CSS) with Node.js and native code. It is open-source, MIT-licensed, and free for both commercial and personal use. In this document, we\u2019ll explain why companies and developers choose Electron."}),"\n",(0,n.jsx)(t.p,{children:"We can split up the benefits of Electron in two questions: First, why should you use web technologies to build your application? Then, why should you choose Electron as the framework to do so?"}),"\n",(0,n.jsxs)(t.p,{children:["If you\u2019re already using web technologies for your application, you can skip straight to the ",(0,n.jsx)(t.code,{children:"Why Electron?"})," section below."]}),"\n",(0,n.jsx)(t.h2,{id:"why-choose-web-technologies",children:"Why choose web technologies"}),"\n",(0,n.jsx)(t.p,{children:"Web technologies include HTML, CSS, JavaScript, and WebAssembly. They\u2019re the storefront of the modern Internet. Those technologies have emerged as the best choice for building user interfaces \u2014 both for consumer applications as well as mission-critical business applications. This is true both for applications that need to run in a browser as well as desktop applications that are not accessible from a browser. Our bold claim here is that this isn\u2019t just true for cross-platform applications that need to run on multiple operating systems but true overall."}),"\n",(0,n.jsxs)(t.p,{children:["As an example, NASA\u2019s actual ",(0,n.jsx)(t.a,{href:"https://github.com/nasa/openmct",children:"Mission Control"})," is written with web technologies. The ",(0,n.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Bloomberg_Terminal",children:"Bloomberg Terminal"}),", the computer system found at every financial institution, is written with web technologies and runs inside Chromium. It costs $25,000 per user, per year. The McDonald\u2019s ordering kiosk, powering the world\u2019s biggest food retailer, is entirely built with Chromium. The ",(0,n.jsx)(t.a,{href:"https://old.reddit.com/r/spacex/comments/gxb7j1/we_are_the_spacex_software_team_ask_us_anything/ft62781/?context=3",children:"SpaceX\u2019s Dragon 2 space capsule"})," uses Chromium to display its interface. You get the point: web technologies are a great tech stack to build user interfaces."]}),"\n",(0,n.jsx)(t.p,{children:"Here are the reasons we, the Electron maintainers, are betting on the web."}),"\n",(0,n.jsx)(t.h3,{id:"versatility",children:"Versatility"}),"\n",(0,n.jsx)(t.p,{children:"Modern versions of HTML and CSS enable your developers and designers to fully express themselves. The web\u2019s showcase includes Google Earth, Netflix, Spotify, Gmail, Facebook, Airbnb, or GitHub. Whatever interface your application needs, you will be able to express it with HTML, CSS, and JavaScript."}),"\n",(0,n.jsx)(t.p,{children:"If you want to focus on building a great product without figuring out how you can realize your designer\u2019s vision in a specific UI framework, the web is a safe bet."}),"\n",(0,n.jsx)(t.h3,{id:"reliability",children:"Reliability"}),"\n",(0,n.jsx)(t.p,{children:"Web technologies are the most-used foundation for user interfaces on the planet. They have been hardened accordingly. Modern computers have been optimized from the CPU to the operating system to be good at running web technologies. The manufacturers of your user\u2019s devices\u2014be that an Android phone or the latest MacBook\u2014will ensure that they can visit websites, play videos on YouTube, or display emails. In turn, they\u2019ll also ensure that your app has a stable foundation, even if you have just one user."}),"\n",(0,n.jsx)(t.p,{children:"If you want to focus on building a great product without debugging a weird quirk that nobody has found before, the web is a safe bet."}),"\n",(0,n.jsx)(t.h3,{id:"interoperability",children:"Interoperability"}),"\n",(0,n.jsx)(t.p,{children:"Whatever provider or customer data you need to interact with, they will have probably thought of an integration path with the web. Depending on your technology choice, embedding a YouTube video either takes 30 seconds or requires you to hire a team devoted to streaming and hardware-accelerated video decoding. In the case of YouTube, using anything other than the provided players is actually against their terms and conditions, so you\u2019ll likely embed a browser frame before you implement your own video streaming decoder."}),"\n",(0,n.jsx)(t.p,{children:"There will be virtually no platform where your app cannot run if you build it with web technologies. Virtually all devices with a display\u2014be that an ATM, a car infotainment system, a smart TV, a fridge, or a Nintendo Switch\u2014come with means to display web technologies. The web is a safe bet if you want to be cross-platform."}),"\n",(0,n.jsx)(t.h3,{id:"ubiquity",children:"Ubiquity"}),"\n",(0,n.jsx)(t.p,{children:"It\u2019s easy to find developers with experience building with web technologies. If you\u2019re a developer, it\u2019ll be easy to find answers to your questions on Google, Stack Overflow, GitHub, or a coding AI of your choice. Whatever problem you need to solve, it\u2019s likely that somebody has solved it well before\u2014and that you can find the answer to the puzzle online."}),"\n",(0,n.jsx)(t.p,{children:"If you want to focus on building a great product with ample access to resources and materials, the web is a safe bet."}),"\n",(0,n.jsx)(t.h2,{id:"why-choose-electron",children:"Why choose Electron"}),"\n",(0,n.jsx)(t.p,{children:"Electron combines Chromium, Node.js, and the ability to write custom native code into one framework for building powerful desktop applications. There are three main reasons to use Electron:"}),"\n",(0,n.jsx)(t.h3,{id:"enterprise-grade",children:"Enterprise-grade"}),"\n",(0,n.jsx)(t.p,{children:"Electron is reliable, secure, stable, and mature. It is the premier choice for companies building their flagship product. We have a list of some of those companies on our homepage, but just among chat apps, Slack, Discord, and Signal are built with Electron. Among AI applications, both OpenAI\u2019s ChatGPT and Anthropic\u2019s Claude use Electron. Visual Studio Code, Loom, Canva, Notion, Docker, and countless other leading developers of software bet on Electron."}),"\n",(0,n.jsx)(t.p,{children:"We did make it a priority to make Electron easy to work with and a delight for developers. That\u2019s likely the main reason why Electron became as popular as it is today \u2014 but what keeps Electron alive and thriving is the maintainer\u2019s focus on making Electron as stable, secure, performant, and capable of mission-critical use cases for end users as possible. We\u2019re building an Electron that is ready to be used in scenarios where unfixable bugs, unpatched security holes, and outages of any kind are worst-case scenarios."}),"\n",(0,n.jsx)(t.h3,{id:"mature",children:"Mature"}),"\n",(0,n.jsx)(t.p,{children:"Our current estimation is that most desktop computers on the planet run at least one Electron app. Electron has grown by prioritizing talent in its maintainer group, fostering excellent and sustainable engineering practices in managing the ongoing maintenance, and proactively inviting companies betting on Electron to directly contribute to the project. We\u2019re an impact project with the OpenJS foundation, which is itself a part of the Linux foundation. We share resources and expertise with other foundation projects like Node.js, ESLint, Webpack - or the Linux Kernel or Kubernetes."}),"\n",(0,n.jsx)(t.p,{children:"What does all of that mean for you, a developer, in practice?"}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Reliable release schedule"}),": Electron will release a new major version in lockstep with every second major Chromium release, usually on the same day as Chromium. A lot of work, both in the form of building processes and tools, but also in terms of raw invested hours every week, has to go into making that happen."]}),"\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"No dictators"}),": Sometimes, betting on a technology also requires you to bet on a single person or company. In turn, it requires you to trust that the person or company never has a breakdown, starts fighting you directly, or does anything else drastic that\u2019ll force you rethink your entire tech stack. Electron is maintained by a diverse set of companies (Microsoft, Slack/Salesforce, Notion, and more) and will continue to welcome more companies interested in ensuring their \u201Cseat at the decision-making table\u201D."]}),"\n"]}),"\n",(0,n.jsx)(t.h3,{id:"stability-security-performance",children:"Stability, security, performance"}),"\n",(0,n.jsx)(t.p,{children:"Electron delivers the best experience on all target platforms (macOS, Windows, Linux) by bundling the latest version of Chromium, V8, and Node.js directly with the application binary. When it comes to running and rendering web content with utmost stability, security, and performance, we currently believe that stack to be \u201Cbest in class\u201D."}),"\n",(0,n.jsx)(t.h4,{id:"why-bundle-anything-at-all",children:"Why bundle anything at all"}),"\n",(0,n.jsx)(t.p,{children:"You might wonder why we bundle Chromium\u2019s web stack with our apps when most modern operating systems already ship a browser and some form of web view. Bundling doesn\u2019t just increase the amount of work for Electron maintainers dramatically, it also increases the total disk size of Electron apps (most apps are >100MB). Many Electron maintainers once developed applications that did make use of embedded web views \u2014 and have since accepted the increased disk size and maintainer work as a worthy trade-off."}),"\n",(0,n.jsx)(t.p,{children:"When using an operating system's built-in web view, you're limited by the browser version included in the oldest operating system version you need to support. We have found the following problems with this approach:"}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Stability"}),": The modern web technology stack is complex, and as a result, you\u2019ll sooner or later encounter bugs. If you use the operating system\u2019s web view, your only recourse will be to ask your customers to upgrade their operating system. If no upgrade is available for that machine (because of no ability to upgrade to the latest macOS or Windows 11), you\u2019ll have to ask them to buy a new computer. If you\u2019re unlucky, you\u2019re now losing a major customer because they will not upgrade their entire fleet of thousands of machines just because one team wanted to try your startup\u2019s app. You have ",(0,n.jsx)(t.em,{children:"no recourse"})," in this situation. Even the risk of that happening is unacceptable to the companies that employ the Electron maintainers."]}),"\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Security:"})," Similar to how you can fix stability bugs by releasing an app update, you can also release security fixes to your application without asking your customer to upgrade their operating system. Even if operating system providers prioritize updates to their built-in browser, we have not seen them reliably update the built-in web views with similar urgency. Bundling a web renderer gives you, the developer, control."]}),"\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Performance:"})," For simple HTML documents, a built-in web view will sometimes use fewer resources than an app with a bundled framework. For bigger apps, it is our experience that we can deliver better performance with the latest version of Chromium than we can with built-in web views. You might think that the built-in view can share a lot of resources with other apps and the operating system\u2014 but for security reasons, apps have to run in their own sandboxes, isolated from each other. At that point, the question is whether the OS\u2019 web view is more performant than Chromium. Across many apps, our experience is that bundling Chromium and Node.js enables us to build better and more performant experiences."]}),"\n"]}),"\n",(0,n.jsx)(t.h4,{id:"why-bundle-chromium-and-nodejs",children:"Why bundle Chromium and Node.js"}),"\n",(0,n.jsx)(t.p,{children:"Electron aims to enable the apps it supports to deliver the best possible user experience, followed by the best possible developer experience. Chromium is currently the best cross-platform rendering stack available. Node.js uses Chromium\u2019s JavaScript engine V8, allowing us to combine the powers of both."}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Native code when you want it"}),": Thanks to Node.js\u2019 mature native addon system, you can always write native code. There is no system API out of reach for you. Whatever macOS, Windows, or Linux feature you\u2019ll want to integrate with \u2014as long as you can do it in C, C++, Objective-C, Rust, or another native language, you\u2019ll be able to do it in Electron. Again, this gives you, the developer, maximum control. With Electron, you can use web technologies without choosing ",(0,n.jsx)(t.em,{children:"only"})," web technologies."]}),"\n"]}),"\n",(0,n.jsx)(t.h3,{id:"developer-experience",children:"Developer experience"}),"\n",(0,n.jsx)(t.p,{children:"To summarize, we aim to build an Electron that is mature, enterprise-grade, and ready for mission-critical applications. We prioritize reliability, stability, security, and performance. That said, you might also choose Electron for its developer experience:"}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Powerful ecosystem"}),": Anything you find on npm will run inside Electron. Any resource available to you about how to work with Node.js also applies to Electron. In addition, Electron itself has a ",(0,n.jsx)(t.a,{href:"https://www.npmjs.com/search?q=electron",children:"thriving ecosystem"})," \u2014 including plenty of choices for installers, updaters, deeper operating system-integration, and more."]}),"\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Plenty of built-in capabilities:"})," Over the last ten years, Electron\u2019s core has gained plenty of native capabilities that you might need to build your application. Written in C++ and Objective-C, Electron has ",(0,n.jsx)(t.a,{href:"https://www.electronjs.org/docs/latest/api/app",children:"dozens of easy-to-use APIs for deeper operating-system integration"})," \u2014 like advanced window customization for transparent or oddly shaped widgets, receiving push notifications from the Apple Push Notification Network, or handling a custom URL protocol for your app."]}),"\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Open source"}),": The entire stack is open source and open to your inspection. This ensures your freedom to add any feature or fix any bug you might encounter in the future."]}),"\n",(0,n.jsxs)(t.li,{children:[(0,n.jsx)(t.strong,{children:"Native code when you need it:"})," It bears repeating that Electron allows you to mix and match web technologies and C++, C, Objective-C, Rust, and other native languages. Whether it be SQLite, a whole LLM, or just the ability to call one specific native API, Electron will make it easy."]}),"\n"]}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"why-choose-something-else",children:"Why choose something else"}),"\n",(0,n.jsxs)(t.p,{children:["As outlined above, the web is an amazing platform for building interfaces. That doesn\u2019t mean that we, the maintainers, would build ",(0,n.jsx)(t.em,{children:"everything"})," with HTML and CSS. Here are some notable exceptions:"]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Resource-Constrained Environments and IoT:"})," In scenarios with very limited memory or processing power (say, one megabyte of memory and 100MHz of processing power on a low-powered ARM Cortex-M), you will likely need to use a low-level language to directly talk to the display to output basic text and images. Even on slightly higher-powered single-chip devices you might want to consider an embedded UI framework. A classic example is a smart watch."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Small Disk Footprint"}),": Zipped Electron apps are usually around 80 to 100 Megabytes. If a smaller disk footprint is a hard requirement, you\u2019ll have to use something else."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Operating System UI Frameworks and Libraries"}),": By allowing you to write native code, Electron can do anything a native application can do, including the use of the operating system\u2019s UI components, like WinUI, SwiftUI, or AppKit. In practice, most Electron apps make rare use of that ability. If you want the majority of your app to be built with operating system-provided interface components, you\u2019ll likely be better off building fully native apps for each operating system you\u2019d like to target. It\u2019s not that it\u2019s impossible with Electron, it\u2019ll just likely be an overall easier development process."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Games and Real-Time Graphics:"})," If you're building a high-performance game or application requiring complex real-time 3D graphics, native frameworks like Unity, Unreal Engine, or DirectX/OpenGL will provide better performance and more direct access to graphics hardware. Web fans might point out caveats, like the fact that even Unreal Engine ships with Chromium \u2014 or that WebGPU and WebGL are developing rapidly and many game engines, including the ones listed here, can now output their games in a format that runs in a browser. That said, if you asked us to build the next AAA game, we\u2019d likely use something else than just web technologies."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Embedding Lightweight Websites"}),": Electron apps typically are mostly web apps with native code sprinkled in where useful. Processing-heavy Electron applications tend to write the UI in HTML/CSS and build the backend in Rust, C++, or another native language. If you\u2019re planning to build a primarily native application that also wants to display a little website in a specific view, you might be better off using the OS-provided web view or something like ",(0,n.jsx)(t.a,{href:"https://ultralig.ht/",children:"ultralight"}),"."]})]})}function d(e={}){let{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(h,{...e})}):h(e)}},84429:function(e,t,o){o.d(t,{R:()=>s,x:()=>a});var i=o(96540);let n={},r=i.createContext(n);function s(e){let t=i.useContext(r);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),i.createElement(r.Provider,{value:t},e.children)}}}]);